   517	  switch (exp->type->spec) {
   518	    case Type::Spec::kChar:
   519	    case Type::Spec::kInt:
   520	    case Type::Spec::kLong:
   521	    case Type::Spec::kLongLong: {
   522	      if (int(exp->type->spec) >= int(to))
