   537	Expr*
   538	Typing::assignment_cast(Expr* lft, Expr* rht)
   539	{
   540	  if (lft->cate != Expr::Cate::kLValue)
   541	    ABORT();
   542	
   543	  switch (lft->type->spec) {
   544	    case Type::Spec::kChar:
   545	    case Type::Spec::kInt:
   546	    case Type::Spec::kLong:
   547	    case Type::Spec::kLongLong:
   548	      break;
   549	
   550	    default:
   551	      ABORT();
   552	  }
   553	  switch (rht->type->spec) {
   554	    case Type::Spec::kChar:
   555	    case Type::Spec::kInt:
   556	    case Type::Spec::kLong:
   557	    case Type::Spec::kLongLong:
   558	      break;
   559	
   560	    default:
   561	      ABORT();
   562	  }
   563	
   564	  rht = ensure_rvalue(rht); // 只能赋右值给变量
   565	
   566	  if (lft->type->texp != nullptr) {
   567	    // 最多只支持数组类型被赋值
   568	    auto arrTy = lft->type->texp->dcst<ArrayType>();
   569	    if (!arrTy) {
   570	      auto pointerType = lft->type->texp->dcst<PointerType>();
   571	      if (pointerType == nullptr)
   572	        ABORT();
   573	      arrTy = pointerType->sub->dcst<ArrayType>();
   574	    }
   575	
   576	    auto arrTy2 = rht->type->texp->dcst<const ArrayType>();
   577	    if (arrTy2 == nullptr) {
   578	      // 指针需要取出其sub类型
   579	      auto pointerType = rht->type->texp->dcst<PointerType>();
   580	      if (pointerType == nullptr)
   581	        ABORT();
   582	
   583	      arrTy2 = pointerType->sub->dcst<const ArrayType>();
   584	    }
   585	
   586	    // 声明符必须相同
   587	    if (lft->type->spec != rht->type->spec)
   588	      ABORT();
   589	
   590	    // non-const 可赋值给 const
   591	    if (lft->type->qual.const_) {
   592	      auto ccst = make<ImplicitCastExpr>();
   593	      ccst->kind = ccst->kNoOp;
   594	      ccst->type = mTypeCache(
   595	        rht->type->spec, Type::Qual{ .const_ = true }, rht->type->texp);
   596	      ccst->sub = rht;
   597	      rht = ccst;
   598	    }
   599	
   600	    // 已知长度的数组可赋值给未知长度的数组
   601	    if (arrTy->len != ArrayType::kUnLen && arrTy2->len == ArrayType::kUnLen)
   602	      ABORT();
   603	
   604	    // 子类型必须相同
   605	    if (*arrTy->sub != *arrTy2->sub)
