   607	  }
   608	
   609	  else if (rht->type->texp != nullptr)
   610	    ABORT();
   611	
   612	  else if (rht->type->spec != lft->type->spec) {
   613	    auto cst = make<ImplicitCastExpr>();
   614	    cst->kind = cst->kIntegralCast;
   615	    cst->type = lft->type;
   616	    cst->sub = rht;
   617	    rht = cst;
