   623	Expr*
   624	Typing::infer_init(Expr* init, const Type* to)
   625	{
   626	  // https://zh.cppreference.com/w/c/language/scalar_initialization
   627	  if (to->texp == nullptr) {
   628	    if (auto p = init->dcst<ImplicitInitExpr>()) {
   629	      p->type = to;
   630	      return p;
   631	    }
   632	
   633	    if (auto p = init->dcst<InitListExpr>()) {
   634	      // 用多个值初始化一个变量时，只有第一个有用，其余的被忽略。
   635	      if (!p->list.empty())
   636	        return infer_init(p->list[0], to);
   637	
   638	      // 空初始化列表即为 ImplicitInitExpr。
   639	      auto ret = make<ImplicitInitExpr>();
   640	      ret->type = to;
   641	      return ret;
   642	    }
   643	
   644	    Expr lft;
   645	    lft.type = to;
   646	    lft.cate = Expr::Cate::kLValue;
   647	    return assignment_cast(&lft, self(init));
   648	  }
   649	
   650	  // https://zh.cppreference.com/w/c/language/array_initialization
   651	  if (auto arrTy = to->texp->dcst<ArrayType>()) {
   652	    if (auto p = init->dcst<ImplicitInitExpr>()) {
   653	      p->type = to;
   654	      return p;
   655	    }
   656	
   657	    // 从花括号环绕列表初始化
   658	    if (auto initList = init->dcst<InitListExpr>()) {
   659	      auto [ret, _] = infer_initlist(initList->list, 0, to);
   660	      return ret;
   661	    }
   662	
   663	    // 从字符串初始化
   664	    if (to->spec == Type::Spec::kChar) {
   665	      init = self(init);
   666	
   667	      auto p = init->type->texp->dcst<ArrayType>();
   668	      if (!p || p->sub != nullptr || init->type->spec != Type::Spec::kChar)
   669	        ABORT();
   670	      if (arrTy->len == -1)
   671	        arrTy->len = p->len;
   672	      else
   673	        p->len = arrTy->len;
   674	
   675	      return init;
   676	    }
   677	
   678	    ABORT();
   679	  }
   680	
   681	  ABORT();
   682	}
   683	
   684	std::pair<Expr*, std::size_t>
   685	Typing::infer_initlist(const std::vector<Expr*>& list,
   686	                       std::size_t begin,
   687	                       const Type* to)
   688	{
   689	  if (to->texp == nullptr) {
   690	    if (begin == list.size())
   691	      return { nullptr, begin };
   692	
   693	    auto ret = infer_init(list[begin], to);
   694	    return { ret, begin + 1 };
   695	  }
   696	
   697	  if (auto arrTy = to->texp->dcst<ArrayType>()) {
   698	    auto ret = make<InitListExpr>();
   699	    ret->type = mTypeCache(to->spec, to->qual, to->texp);
   700	    ret->cate = Expr::Cate::kRValue;
   701	
   702	    Type elemTy;
   703	    elemTy.spec = to->spec;
   704	    elemTy.qual = to->qual;
   705	    elemTy.texp = arrTy->sub;
   706	
   707	    if (arrTy->len == ArrayType::kUnLen) {
   708	      arrTy->len = 0;
   709	      while (begin < list.size()) {
   710	        auto [expr, next] = infer_initlist(list, begin, &elemTy);
   711	        ret->list.push_back(expr);
   712	        begin = next;
   713	        ++arrTy->len;
   714	      }
   715	    }
   716	
   717	    else {
   718	      for (int i = 0; i < arrTy->len; ++i) {
   719	        if (begin == list.size())
   720	          break;
   721	        auto [expr, next] = infer_initlist(list, begin, &elemTy);
   722	        ret->list.push_back(expr);
   723	        begin = next;
   724	      }
   725	    }
   726	
   727	    return { ret, begin };
   728	  }
   729	
   730	  ABORT();
   731	}
